class LoginActivity : AppCompatActivity() {

    private lateinit var authManager: AuthManager

    private lateinit var etEmail: EditText
    private lateinit var etPassword: EditText
    private lateinit var btnLogin: Button
    private lateinit var btnLogout: Button
    private lateinit var tvStatus: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authManager = AuthManager.getInstance(this)

        // Check if already logged in on app restart
        if (authManager.isLoggedIn) {
            val token = authManager.getAuthToken()
            val userId = authManager.currentUserId
            val email = authManager.currentUserEmail

            // Check session expiry (e.g., 7 days)
            val sevenDaysMillis = 7L * 24 * 60 * 60 * 1000
            if (authManager.isSessionExpired(sevenDaysMillis)) {
                Toast.makeText(this, "Session expired. Please login again.", Toast.LENGTH_SHORT).show()
                authManager.logout()
            } else {
                Toast.makeText(
                    this,
                    "Welcome back! User: $email (ID: $userId)",
                    Toast.LENGTH_SHORT
                ).show()
                navigateToMain()
                return
            }
        }

        setupLoginUI()
    }

    private fun setupLoginUI() {
        etEmail = EditText(this).apply {
            hint = "Email"
            id = android.view.View.generateViewId()
        }
        etPassword = EditText(this).apply {
            hint = "Password"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
            id = android.view.View.generateViewId()
        }
        btnLogin = Button(this).apply {
            text = "Login"
            setOnClickListener { performLogin() }
        }
        btnLogout = Button(this).apply {
            text = "Logout"
            setOnClickListener { performLogout() }
        }
        tvStatus = TextView(this).apply {
            text = "Please login"
            textSize = 16f
        }

        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
