            addView(etPassword)
            addView(btnLogin)
            addView(btnLogout)
        }

        setContentView(layout)
        updateStatusUI()
    }

    private fun performLogin() {
        val email = etEmail.text.toString().trim()
        val password = etPassword.text.toString().trim()

        if (email.isEmpty() || password.isEmpty()) {
            Toast.makeText(this, "Please fill in all fields", Toast.LENGTH_SHORT).show()
            return
        }

        // Simulate authentication API call
        simulateAuthApiCall(email, password) { success, token, userId ->
            if (success && token != null && userId != null) {
                // Save auth session on successful login
                authManager.saveAuthSession(
                    authToken = token,
                    userId = userId,
                    email = email,
                    displayName = email.substringBefore("@")
                )

                Toast.makeText(this, "Login successful!", Toast.LENGTH_SHORT).show()
                updateStatusUI()
                navigateToMain()
            } else {
                Toast.makeText(this, "Login failed. Check credentials.", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun performLogout() {
        authManager.logout()
        Toast.makeText(this, "Logged out successfully", Toast.LENGTH_SHORT).show()
        updateStatusUI()
    }

    private fun updateStatusUI() {
        if (authManager.isLoggedIn) {
            tvStatus.text = "Logged in as: ${authManager.currentUserEmail}\n" +
                    "User ID: ${authManager.currentUserId}\n" +
